const novel = $('Merge Context').first().json.novel;
const outline = $('Merge Context').first().json.outline;
const characters = $('Merge Context').first().json.characters;
const styleSheet = $('Merge Context').first().json.styleSheet;

// Parse chapter breaks from the novel
const chapterRegex = /Chapter \d+:\s*[^\n]+/g;
const chapters = [];
let match;
const matches = [];

while ((match = chapterRegex.exec(novel)) !== null) {
  matches.push({ title: match[0].trim(), index: match.index });
}

for (let i = 0; i < matches.length; i++) {
  const start = matches[i].index;
  const end = i + 1 < matches.length ? matches[i + 1].index : novel.length;
  chapters.push({
    chapterNumber: i + 1,
    chapterTitle: matches[i].title,
    chapterText: novel.slice(start, end).trim(),
    outline,
    characters,
    styleSheet
  });
}

return chapters.map(ch => ({ json: ch }));

const item = $input.item.json;

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://<OLLAMA_HOST>:<PORT>/api/chat',
  headers: {
    'Content-Type': 'application/json'
  },
  body: {
    model: '<MODEL_NAME>',
    messages: [{
      role: 'user',
      content: `You are a professional literary editor reviewing a novel chapter. Analyze the chapter below against the reference materials and produce structured editorial notes.

FORMAT YOUR RESPONSE EXACTLY LIKE THIS:

CHAPTER ${item.chapterNumber}: ${item.chapterTitle}
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

CONTINUITY ISSUES:
[List any continuity errors found. For each issue specify the exact location as "Para X" or quote the relevant sentence. If none found, write "None identified."]

EDITORIAL NOTES:
[List structural, pacing, or narrative issues. Be specific about location. If none found, write "None identified."]

AI PROSE FLAGS:
[List any phrases or patterns from the anti-AI filter or generic AI writing that appear in this chapter. Quote the exact phrase and note its location. If none found, write "None identified."]

MISSING OUTLINE BEATS:
[List any beats from the outline that appear to be missing or underdeveloped in the chapter. If none found, write "None identified."]

STRENGTHS:
[Note 2-3 things working well in this chapter.]

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

REFERENCE MATERIALS:

OUTLINE FOR THIS CHAPTER:
${item.outline}

CHARACTER BIBLE:
${item.characters}

STYLE SHEET:
${item.styleSheet}

CHAPTER TEXT TO ANALYZE:
${item.chapterText}`
    }],
    stream: false
  },
  json: true
});

const notes = response.message.content;

return {
  chapterNumber: item.chapterNumber,
  chapterTitle: item.chapterTitle,
  notes
};
